#!/bin/bash# Fichaje Deploy - Direct execution via SSH# This script should be executed on the VPS directlyset -eAPP_DIR="/opt/fichaje"REPO_URL="https://github.com/DiegoERuiz/fichaje.git"echo "â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"echo "FICHAJE DEPLOYMENT - Linux/VPS"echo "â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"echo ""echo "[1/15] Creating directories..."mkdir -p $APP_DIRcd $APP_DIRecho "[2/15] Updating system..."apt-get update -qqapt-get upgrade -y -qqecho "[3/15] Installing Docker..."curl -fsSL https://get.docker.com -o get-docker.sh 2>/dev/nullsh get-docker.sh > /dev/null 2>&1rm get-docker.shecho "[4/15] Installing Docker Compose..."curl -L "https://github.com/docker/compose/releases/latest/download/docker-compose-$(uname -s)-$(uname -m)" -o /usr/local/bin/docker-compose 2>/dev/nullchmod +x /usr/local/bin/docker-composeecho "[5/15] Starting Docker..."systemctl start dockersystemctl enable docker > /dev/null 2>&1echo "[6/15] Cloning repository..."cd /optrm -rf fichaje 2>/dev/null || truegit clone $REPO_URL fichajecd fichajeecho "[7/15] Installing Java 11..."apt-get install -y -qq openjdk-11-jdk mavenecho "[8/15] Building backend (may take 10 minutes)..."cd $APP_DIR/apps/fichaje-bemvn clean package -DskipTests -qecho "[9/15] Installing Node.js..."curl -fsSL https://deb.nodesource.com/setup_18.x | bash - > /dev/null 2>&1apt-get install -y -qq nodejsecho "[10/15] Building frontend..."cd $APP_DIR/apps/fichaje-fenpm install > /dev/null 2>&1npm run build -- --prod > /dev/null 2>&1echo "[11/15] Installing Certbot..."apt-get install -y -qq certbot python3-certbot-nginxecho "[12/15] Generating SSL certificate..."certbot certonly --standalone \    -d fichajes.biedma.com \    --non-interactive \    --agree-tos \    -m admin@fichajes.biedma.com 2>/dev/null || echo "Certificate may exist"echo "[13/15] Generating keystore..."cd $APP_DIRSSL_KEYSTORE_PASSWORD="gkZJWOo3fP-SaiMM"openssl pkcs12 -export \    -in /etc/letsencrypt/live/fichajes.biedma.com/fullchain.pem \    -inkey /etc/letsencrypt/live/fichajes.biedma.com/privkey.pem \    -out $APP_DIR/fichajes-keystore.p12 \    -name fichaje \    -passout pass:${SSL_KEYSTORE_PASSWORD} 2>/dev/null || trueecho "[14/15] Starting Docker Compose..."docker-compose -f docker-compose-prod.yml up -decho "[15/15] Waiting for services to start..."sleep 30echo ""echo "âœ“ Deployment steps completed!"docker-compose -f docker-compose-prod.yml ps

